import React, { useEffect, useState } from 'react'
import PlaceAttributes from "../assets/PlaceAttributes.json";
import Hydrological_Images from "../assets/Hydrological_Images.json"
import { colors } from '@mui/material';
import { useSelectedFeatureContext } from '../contexts/SelectedFeatureContext';
import { useLoaderContext } from '../contexts/LoaderContext';

const HydrologicalPage = () => {
  const { handleDistrictSelect, handleTehsilSelect, selectedDistrict, selectedTehsil, tehsilList } = useSelectedFeatureContext();
  const { setIsLoading } = useLoaderContext();
  const [selectedImage, setSelectedImage] = useState(null);




  useEffect(() => {
    if (selectedTehsil && selectedTehsil !== '') {

      let item = Hydrological_Images.find((item) => item.TEHSIL === selectedTehsil);
      setSelectedImage(item);

    }
  }, [selectedTehsil]);




  return (
    <div className='dasboard_page_container'>

      <div className='main_dashboard'>
        <div className='left_panel'>
          <div className="left_panel_container">

            <div className=' border-secondary p-2 mb-2'>

              <label className=''>Select district</label>
              <select className="form-select mb-3"
                value={selectedDistrict ? selectedDistrict : ''}
                onChange={handleDistrictSelect}>
                <option value="">Select</option>
                {[...new Set(PlaceAttributes.map((item) => item.DISTRICT))].map((item, index) =>
                  <option key={index} value={item}>{item}</option>
                )}
              </select>



              <label className='mt-3'>Select taluka</label>
              <select className="form-select mb-2"
                value={selectedTehsil ? selectedTehsil : ''}
                disabled={tehsilList && tehsilList.length === 0}
                onChange={handleTehsilSelect} >
                <option value="">Select</option>
                {[...new Set(tehsilList && tehsilList.map((item) => item.TEHSIL))].map((item, index) =>
                  <option key={index} value={item}>{item}</option>
                )}
              </select>

            </div>
          </div>

        </div>

        <div className='right_panel'>
          <div className='right_panel_container'>
            {selectedImage ? (
              <>
                <img src={selectedImage.url} alt='Hydrological Conditions' />
                <div className="para_content">




                  <h1>Soil-Moisture Percentile: </h1>
                  <p>Soil-moisture percentile shows the current soil moisture conditions (dry/wet) compared to all past measurements. For examples, If current soil-moisture is 90th percentile, that means it is wetter than 90% of all past measurements. If it is 10th percentile, the soil is drier than 90% of all past measurements.
                  </p>

                  <h1>Legend</h1>
                  <div className='item_table_container'>
                    <table className='item_table'>
                      <thead>
                        <tr>
                          <th>Dry Condition:</th>
                          <th>Wet Condition:</th>
                        </tr>
                      </thead>
                      <tbody>
                        <tr>
                          <td>30th﹤Percentile ≤ 70th  (Normal Conditions) <br />

                            20th﹤Percentile ≤ 30th   <span style={{ color: "red" }}>(Abnormally Dry)</span><br />

                            10th﹤Percentile ≤ 20th   <span style={{ color: "red" }}>(Moderate Dry)</span><br />

                            5th﹤Percentile ≤ 10th     <span style={{ color: "red" }}>(Severe Dry)</span> <br />

                            2nd﹤Percentile ≤  5th     <span style={{ color: "red" }}>(Extreme Dry)</span><br />

                            0th﹤ Percentile ≤ 2nd    <span style={{ color: "red" }}>(Exceptional Dry)</span></td>
                          <td>70th﹤Percentile ≤ 80th        <span style={{ color: "blue" }}>(Abnormally Wet)</span> <br />

                            80th﹤Percentile ≤ 90th        <span style={{ color: "blue" }}> (Moderate Wet)</span>  <br />

                            90th﹤Percentile ≤ 95th         <span style={{ color: "blue" }}>(Severe Wet)</span>  <br />

                            95nd﹤Percentile ≤  98th       <span style={{ color: "blue" }}> (Extreme Wet)</span> <br />

                            98th﹤Percentile ≤  100th       <span style={{ color: "blue" }}>(Exceptional Wet)</span> </td>
                        </tr>

                      </tbody>
                    </table>
                  </div>

                </div>

              </>
            ) : (
              <p>
                Please select location.
              </p>
            )}

          </div>
        </div>

      </div>
    </div>
  )
}

export default HydrologicalPage